WASM_IMPORT_SIGNATURE_BY_NAME: dict[str, tuple[tuple[str, ...], tuple[str, ...]]] = {
    name: (params, results)
    for name, params, results in WASM_IMPORT_SIGNATURES
}

def wasm_import_signature(import_name: str) -> tuple[tuple[str, ...], tuple[str, ...]] | None:
    return WASM_IMPORT_SIGNATURE_BY_NAME.get(import_name)

def wasm_import_result_kind(import_name: str) -> str | None:
    signature = wasm_import_signature(import_name)
    if signature is None:
        return None
    results = signature[1]
    return "nil" if not results else ", ".join(results)

